SELECT proj.project_name, proj.belong_province, proj.belong_city, proj.belong_district, proj.compensation_money, proj.compensation_date, proj.transfer_date, proj.manage, proj.project_state, law.name as lawFirmName,
FROM project_info_ext t0 JOIN project_info proj ON t0.id=proj.id left join law_firm_info law on proj.law_firm_id = law.id and law.is_deleted = 0
AND proj.project_name LIKE CONCAT ('%',#{request.projectName},'%')
AND proj.manage LIKE CONCAT ('%',#{request.manage},'%')
AND proj.compensation_date BETWEEN
#{item}
AND (proj.affiliated_org IN #{item} OR
proj.manage LIKE CONCAT('%',#{item},'%')
)
AND ( proj.manage LIKE CONCAT('%',#{item},'%')
)
AND t0.industry_type = #{request.industryType}
AND proj.project_state = #{request.projectState}
AND proj.project_state in
#{item}

SELECT

FROM project_info_ext t0


    AND t0.create_stamp BETWEEN

      #{item}



    AND t0.id = #{request.id}


    AND t0.tenant_id = #{request.tenantId}


    AND t0.creator = #{request.creator}


    AND t0.create_stamp = #{request.createStamp}


    AND t0.last_editor = #{request.lastEditor}


    AND t0.last_edit_stamp = #{request.lastEditStamp}


    AND t0.type = #{request.type}


    AND t0.cooperate_bank = #{request.cooperateBank}


    AND t0.cooperate_bank_branch = #{request.cooperateBankBranch}


    AND t0.industry_type = #{request.industryType}


    AND t0.product_name = #{request.productName}


    AND t0.big_small = #{request.bigSmall}


    AND t0.gover_type = #{request.goverType}


    AND t0.debt_begin_date = #{request.debtBeginDate}


    AND t0.debt_end_date = #{request.debtEndDate}


    AND t0.loan_money = #{request.loanMoney}


    AND t0.pact_code = #{request.pactCode}


    AND t0.loan_code = #{request.loanCode}


    AND t0.guarantee_rate = #{request.guaranteeRate}


    AND t0.risk_compensation = #{request.riskCompensation}


    AND t0.aid = #{request.aid}


    AND t0.aname = #{request.aname}


    AND t0.acode = #{request.acode}


    AND t0.bid = #{request.bid}


    AND t0.bcode = #{request.bcode}


    AND t0.bname = #{request.bname}


    AND t0.loan_pact_code = #{request.loanPactCode}


    AND t0.relation_enterprise = #{request.relationEnterprise}


    AND t0.relation_enterprise_no = #{request.relationEnterpriseNo}


    AND t0.pled_pact_code = #{request.pledPactCode}




    ORDER BY ${request.field} ${request.order}


    ORDER BY t0.id DESC
